#[cfg(test)]
mod tests {
    use super::*;
    use std::env;

    #[test]
    fn save_and_load_cache_roundtrip() {
        let mut cache = Cache::new(1);

        let mut metadata = HashMap::new();
        metadata.insert("region".into(), "us-east".into());
        metadata.insert("plan".into(), "pro".into());

        let mut widget_state = HashMap::new();
        widget_state.insert("filter".into(), "favorites".into());

        cache.insert_user(
            "user_123",
            UserPreferences {
                profile: UserProfile {
                    display_name: "Alice".into(),
                    language: "en-US".into(),
                    timezone: "UTC".into(),
                },
                theme: Theme::Custom {
                    background: "#111111".into(),
                    foreground: "#eeeeee".into(),
                    accent: "#33aaff".into(),
                    font_scale: 1.15,
                },
                notifications: NotificationSettings {
                    email: DeliveryPreference::ImportantOnly,
                    push: DeliveryPreference::All,
                    sms: DeliveryPreference::Disabled,
                    digest: DigestFrequency::Weekly,
                },
                privacy: PrivacySettings {
                    profile_visibility: Visibility::Public,
                    activity_visibility: Visibility::ContactsOnly,
                    searchable: true,
                    data_sharing: DataSharing::AnonymousAnalytics,
                },
                shortcuts: vec![
                    Shortcut {
                        action: "save".into(),
                        keybinding: Keybinding::Single("Ctrl+S".into()),
                        enabled: true,
                    },
                    Shortcut {
                        action: "command_palette".into(),
                        keybinding: Keybinding::Chord(vec!["Ctrl+K".into(), "Ctrl+P".into()]),
                        enabled: true,
                    },
                ],
                widgets: vec![
                    WidgetConfig {
                        id: "weather".into(),
                        placement: WidgetPlacement::Sidebar,
                        refresh_interval_secs: 300,
                        state: WidgetState::Expanded,
                    },
                    WidgetConfig {
                        id: "favorites".into(),
                        placement: WidgetPlacement::Dashboard { column: 2, order: 1 },
                        refresh_interval_secs: 60,
                        state: WidgetState::Custom(widget_state),
                    },
                ],
                metadata,
            },
        );

        let path = env::temp_dir().join("user_prefs_cache_test.bin");
        cache.save_to_path(&path).unwrap();
        let loaded = Cache::load_from_path(&path).unwrap();

        assert_eq!(cache, loaded);

        let _ = std::fs::remove_file(path);
    }
}